const apiKey = 'sk-nU7RSKnbZIOwH607r3MfbW5HmP6NIaj1aGVPFGcNDDiL0h5u';
const model = 'gemini-1.5-pro';
const url = 'https://ai.juguang.chat/v1/chat/completions';
const ctx = String($input.first().json.conversation_context || '').trim();

if (!ctx) {
  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }] } }];
}

const headers = {
  'Authorization': `Bearer ${apiKey}`,
  'Content-Type': 'application/json'
};

const body = {
  model: model,
  messages: [
    {
      role: 'system',
      content: 'You are a personality detector. Infer Big Five from the user text for THIS TURN ONLY. Return JSON ONLY exactly as: {"ocean_disc":{"O":-1|0|1,"C":-1|0|1,"E":-1|0|1,"A":-1|0|1,"N":-1|0|1}} No prose.'
    },
    {
      role: 'user',
      content: `Text: ${ctx}`
    }
  ],
  temperature: 0.1,
  max_tokens: 200
};

try {
  const res = await this.helpers.httpRequest({
    method: 'POST',
    url: url,
    headers: headers,
    body: body,
    timeout: 20000
  });
  return [{ json: res.json || res }];
} catch (error) {
  return [{ json: { choices: [{ message: { content: '{"ocean_disc":{"O":0,"C":0,"E":0,"A":0,"N":0}}' } }], error: error.message } }];
}

const allInputs = $input.all();
const det = allInputs[0]?.json || {};
const raw = det?.choices?.[0]?.message?.content ?? '';

let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[^}]*\}/); 
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      parsed = {};
    }
  }
}

let oceanDisc = parsed?.ocean_disc;
if (!oceanDisc && parsed?.ocean) {
  const thr = 0.2;
  const o = parsed.ocean;
  const sign = (v) => (v >= thr ? 1 : (v <= -thr ? -1 : 0));
  oceanDisc = {
    O: sign(o.O || 0),
    C: sign(o.C || 0), 
    E: sign(o.E || 0),
    A: sign(o.A || 0),
    N: sign(o.N || 0)
  };
}

const od = oceanDisc || { O: 0, C: 0, E: 0, A: 0, N: 0 };

let ingest = null;
if (allInputs.length > 1) {
  ingest = allInputs[1]?.json || null;
}

const turnText = ingest?.clean_msg || '';
const sessionId = ingest?.session_id || '';

return [{
  json: {
    ocean_disc: od,
    turn_text: turnText,
    session_id: sessionId
  }
}];

